		},
	)
}

func writeGoldenHarnessScript(t *testing.T, dir, name, body string) {
	t.Helper()
	path := filepath.Join(dir, name)
	if err := os.WriteFile(path, []byte(body), 0o755); err != nil {
		t.Fatalf("write harness cassette script %s: %v", name, err)
	}
}

